import{_ as a,o as t,c as s,a5 as i}from"./chunks/framework.JW9VOlAI.js";const k=JSON.parse('{"title":"Account CR","description":"","frontmatter":{},"headers":[],"relativePath":"concepts/account-cr.md","filePath":"concepts/account-cr.md"}'),o={name:"concepts/account-cr.md"};function n(r,e,l,h,c,p){return t(),s("div",null,[...e[0]||(e[0]=[i(`<h1 id="account-cr" tabindex="-1">Account CR <a class="header-anchor" href="#account-cr" aria-label="Permalink to &quot;Account CR&quot;">​</a></h1><p>The <strong>Account</strong> is the central Platform Mesh custom resource that represents an organization, team, project, or environment in the <a href="/pr-preview/pr-80/concepts/account-model.html">account hierarchy</a>. Each Account corresponds to a kcp workspace and is the unit at which Platform Mesh provisions identity, authorization, and policy.</p><div class="info custom-block"><p class="custom-block-title">Where it comes from</p><p>The Account CR is defined by the <a href="https://github.com/platform-mesh/account-operator" target="_blank" rel="noreferrer">account-operator</a> in the API group <code>core.platform-mesh.io/v1alpha1</code>. The operator reconciles Accounts into kcp workspaces, sets up workspace types, and wires identity/authorization for each one.</p></div><h2 id="schema" tabindex="-1">Schema <a class="header-anchor" href="#schema" aria-label="Permalink to &quot;Schema&quot;">​</a></h2><p>A minimal Account looks like this:</p><div class="language-yaml vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">yaml</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">apiVersion</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">core.platform-mesh.io/v1alpha1</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">kind</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">Account</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">metadata</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">  name</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">platform-team</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">spec</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">  type</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">org</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">              # org | folder</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">  displayName</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;Platform Team&quot;</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">  creator</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">alice@example.com</span></span></code></pre></div><table tabindex="0"><thead><tr><th>Field</th><th>Purpose</th></tr></thead><tbody><tr><td><code>spec.type</code></td><td>Account type. <code>org</code> for a root organization (mapped to a kcp workspace type), <code>folder</code> for a sub-account / nesting level.</td></tr><tr><td><code>spec.displayName</code></td><td>Human-readable label used by the Portal and marketplace.</td></tr><tr><td><code>spec.creator</code></td><td>The user who owns the Account, used as the initial admin in the IAM store.</td></tr><tr><td><code>spec.extensions</code></td><td>Optional list of <code>AccountExtension</code> resources that attach additional configuration to the Account (e.g., quotas, custom policies).</td></tr><tr><td><code>spec.data</code></td><td>Free-form structured data the Account exposes to the Portal and to children for inheritance.</td></tr></tbody></table><h2 id="who-creates-it" tabindex="-1">Who Creates It <a class="header-anchor" href="#who-creates-it" aria-label="Permalink to &quot;Who Creates It&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Account type</th><th>Created by</th></tr></thead><tbody><tr><td>Root organization (<code>type: org</code>)</td><td>Platform owner, usually as part of onboarding a new tenant. Typically committed in <code>helm-charts/local-setup</code> or a similar GitOps repo.</td></tr><tr><td>Folder / sub-account (<code>type: folder</code>)</td><td>The parent account&#39;s admin (delegated through OpenFGA), often via the Portal or <code>kubectl</code>.</td></tr></tbody></table><p>The Account CR is <strong>not</strong> created by service providers or service consumers directly. Providers and consumers operate inside workspaces that the Account hierarchy provisions for them.</p><h2 id="what-happens-when-you-apply-one" tabindex="-1">What Happens When You Apply One <a class="header-anchor" href="#what-happens-when-you-apply-one" aria-label="Permalink to &quot;What Happens When You Apply One&quot;">​</a></h2><p>When the account-operator sees a new Account CR, it:</p><ol><li><strong>Creates a kcp workspace</strong> for the Account under its parent (or at root for <code>type: org</code>).</li><li><strong>Sets workspace type</strong> based on <code>spec.type</code>, applying the right RBAC and initialization policies for an org or folder.</li><li><strong>Provisions an IAM Store</strong> (OpenFGA store) for this Account — see <a href="/pr-preview/pr-80/concepts/iam-store.html">IAM Store</a> for details.</li><li><strong>Initializes identity</strong> — for <code>org</code> accounts, a Keycloak realm is created (or referenced if federation is configured).</li><li><strong>Adds finalizers</strong> (<code>account.core.platform-mesh.io/finalizer</code>, <code>workspacetype.core.platform-mesh.io/finalizer</code>) so deletion is reconciled in the right order.</li><li><strong>Writes status</strong> with the workspace path, the IAM store name, and references to the identity realm.</li></ol><p>The Account becomes ready when all of the above complete. Until then, the workspace exists but is not usable for binding services or onboarding users.</p><h2 id="example-a-real-account-from-local-setup" tabindex="-1">Example: A Real Account from local-setup <a class="header-anchor" href="#example-a-real-account-from-local-setup" aria-label="Permalink to &quot;Example: A Real Account from local-setup&quot;">​</a></h2><p>The following is the root organization account from the Platform Mesh local setup:</p><div class="language-yaml vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">yaml</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">apiVersion</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">core.platform-mesh.io/v1alpha1</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">kind</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">Account</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">metadata</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">  name</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">default</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">spec</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">  type</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">org</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">  displayName</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">platform-mesh Org</span></span></code></pre></div><p>Applied at the root workspace, this provisions the top-level <code>platform-mesh</code> organization that all other accounts are children of in a default deployment.</p><h2 id="where-this-appears" tabindex="-1">Where This Appears <a class="header-anchor" href="#where-this-appears" aria-label="Permalink to &quot;Where This Appears&quot;">​</a></h2><ul><li><a href="/pr-preview/pr-80/guides/provider-quick-start.html">Provider Quick Start</a> — the provider workspace lives under an Account in the hierarchy</li><li><a href="/pr-preview/pr-80/concepts/account-model.html">Account Model</a> — the structural overview</li><li><a href="/pr-preview/pr-80/concepts/iam-store.html">IAM Store</a> — what gets provisioned alongside each Account</li></ul><h2 id="what-s-next" tabindex="-1">What&#39;s Next <a class="header-anchor" href="#what-s-next" aria-label="Permalink to &quot;What&#39;s Next&quot;">​</a></h2><ul><li><a href="/pr-preview/pr-80/concepts/account-model.html"><strong>Account Model</strong></a> — how Accounts compose into a hierarchy</li><li><a href="/pr-preview/pr-80/concepts/iam-store.html"><strong>IAM Store</strong></a> — the OpenFGA store provisioned per Account</li><li><a href="/pr-preview/pr-80/concepts/pm-annotations.html"><strong>Platform Mesh Annotations</strong></a> — the labels and finalizers PM uses on Accounts and related objects</li></ul>`,22)])])}const u=a(o,[["render",n]]);export{k as __pageData,u as default};
